  if (!projects[id]) {
    throw new AppError('Project not found', 404);
  }
  return projects[id];
};

// Tasks
const setTask = (projectId, task) => {
  if (!projects[projectId]) {
    throw new AppError('Project not found', 404);
  }
  if (!tasks[projectId]) {
    tasks[projectId] = {};
  }
  tasks[projectId][task.id] = task;
};

