  if (!projects[projectId]) {
    throw new AppError('Project not found', 404);
  }
  if (!tasks[projectId] || !tasks[projectId][taskId]) {
    throw new AppError('Task not found', 404);
  }
  return tasks[projectId][taskId];
};

